func (s *ProductService) CreateProduct(ctx context.Context, req *CreateProductRequest) (*Product, error) {
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	if req.Price <= 0 {
		return nil, status.Error(codes.InvalidArgument, "price must be greater than 0")
	}

	return &Product{
		ProductId:   fmt.Sprintf("prod_%d", time.Now().Unix()),
		Name:        req.Name,
		Description: req.Description,
		Price:       req.Price,
		InStock:     true,
	}, nil
}

